import{_ as i,o as r,c as e,ag as o,j as l,a}from"./chunks/framework.Cqf6AMW8.js";const _=JSON.parse('{"title":"CSS 基础选择器","description":"CSS 基础选择器、复合选择器和伪选择器的使用方法。","frontmatter":{"title":"CSS 基础选择器","description":"CSS 基础选择器、复合选择器和伪选择器的使用方法。","date":"2026-04-21T00:00:00.000Z","tags":["CSS","选择器"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/css/CSS-基础-1-选择器.md","filePath":"docs/frontend/css/CSS-基础-1-选择器.md","lastUpdated":1776715536000}'),n={name:"docs/frontend/css/CSS-基础-1-选择器.md"};function s(d,t,h,p,c,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="前端" tabindex="-1">前端 <a class="header-anchor" href="#前端" aria-label="Permalink to &quot;前端&quot;">​</a></h1><p>======================================================</p><h2 id="_1-书写样式-常用" tabindex="-1">1. 书写样式（常用） <a class="header-anchor" href="#_1-书写样式-常用" aria-label="Permalink to &quot;1. 书写样式（常用）&quot;">​</a></h2><ul><li><p>写一个.CSS文件</p></li><li><p>在HTML里用link标签引用CSS</p></li><li><p><strong>link标签</strong>：</p><ul><li>link写在title下</li><li>rel关系 href位置</li></ul></li></ul><p>======================================================</p><h2 id="_2-基础选择器" tabindex="-1">2. 基础选择器 <a class="header-anchor" href="#_2-基础选择器" aria-label="Permalink to &quot;2. 基础选择器&quot;">​</a></h2><h3 id="_2-1-类选择器" tabindex="-1">2.1 类选择器 <a class="header-anchor" href="#_2-1-类选择器" aria-label="Permalink to &quot;2.1 类选择器&quot;">​</a></h3><ul><li><p><strong>定义</strong>：.类名</p></li><li><p><strong>调用</strong>：头标签添加属性 class=&quot;类名&quot;</p></li><li><p><strong>说明</strong>：选择器可以给多个标签使用</p></li><li><p><strong>作用</strong>：实际书写中，父级选择器均使用类选择器</p></li></ul><h3 id="_2-2-标签选择器" tabindex="-1">2.2 标签选择器 <a class="header-anchor" href="#_2-2-标签选择器" aria-label="Permalink to &quot;2.2 标签选择器&quot;">​</a></h3>',9),l("ul",null,[l("li",{"属性:属性值":""},[l("p",null,[l("strong",null,"格式"),a("：标签")])]),l("li",null,[l("p",null,[l("strong",null,"说明"),a("：同名标签都一个样式")])]),l("li",null,[l("p",null,[l("strong",null,"作用"),a("：一般用于子选择")])])],-1),l("h3",{id:"_2-3-通配符选择器",tabindex:"-1"},[a("2.3 通配符选择器 "),l("a",{class:"header-anchor",href:"#_2-3-通配符选择器","aria-label":'Permalink to "2.3 通配符选择器"'},"​")],-1),l("ul",null,[l("li",{属性:""},[l("strong",null,"格式"),a("：* "),l("ul",null,[l("li",null,[l("strong",null,"作用"),a("：用于初始化页面，CSS相关内容里有模板")])])])],-1),o('<p>======================================================</p><h2 id="_3-css复合选择器" tabindex="-1">3. CSS复合选择器 <a class="header-anchor" href="#_3-css复合选择器" aria-label="Permalink to &quot;3. CSS复合选择器&quot;">​</a></h2><p>%% 一般使用父级选择器就行很少使用其他几个 %%</p><h3 id="_3-1-父级选择器" tabindex="-1">3.1 父级选择器 <a class="header-anchor" href="#_3-1-父级选择器" aria-label="Permalink to &quot;3.1 父级选择器&quot;">​</a></h3><ul><li><p><strong>格式</strong>：选择器1 选择器2 选择器3...</p></li><li><p><strong>示例</strong>：<code>div p</code>、<code>.nav a</code></p></li><li><p><strong>作用</strong>：选择指定元素的所有后代元素</p></li><li><p><strong>特点</strong>：空格分隔，层级关系</p></li></ul><p>======================================================</p><h2 id="_4-伪选择器" tabindex="-1">4. 伪选择器 <a class="header-anchor" href="#_4-伪选择器" aria-label="Permalink to &quot;4. 伪选择器&quot;">​</a></h2><h3 id="_4-1-伪链接选择器" tabindex="-1">4.1 伪链接选择器 <a class="header-anchor" href="#_4-1-伪链接选择器" aria-label="Permalink to &quot;4.1 伪链接选择器&quot;">​</a></h3><h4 id="语法" tabindex="-1">语法 <a class="header-anchor" href="#语法" aria-label="Permalink to &quot;语法&quot;">​</a></h4><ul><li><strong>示例</strong>：<code>a:hover</code></li></ul><h4 id="超链接伪类状态" tabindex="-1">超链接伪类状态 <a class="header-anchor" href="#超链接伪类状态" aria-label="Permalink to &quot;超链接伪类状态&quot;">​</a></h4><ul><li><p><strong>:link</strong>：未被访问过的链接</p></li><li><p><strong>:visited</strong>：已被访问过的链接</p></li><li><p><strong>:hover</strong>：鼠标悬停的链接</p></li><li><p><strong>:active</strong>：正在被点击的链接</p></li></ul><h4 id="超链接伪类顺序" tabindex="-1">超链接伪类顺序 <a class="header-anchor" href="#超链接伪类顺序" aria-label="Permalink to &quot;超链接伪类顺序&quot;">​</a></h4><ul><li><strong>顺序</strong>：<code>:link</code> → <code>:visited</code> → <code>:hover</code> → <code>:active</code></li></ul><h3 id="_4-2-伪结构选择器" tabindex="-1">4.2 伪结构选择器 <a class="header-anchor" href="#_4-2-伪结构选择器" aria-label="Permalink to &quot;4.2 伪结构选择器&quot;">​</a></h3><ul><li><p><strong>:first-child</strong>：选择父元素的第一个子元素</p></li><li><p><strong>:last-child</strong>：选择父元素的最后一个子元素</p></li><li><p><strong>:nth-child(n)</strong>：选择父元素的第n个子元素</p></li><li><p><strong>:nth-last-child(n)</strong>：从父元素的最后一个子元素开始计数，选择第n个元素</p></li></ul><h3 id="_4-3-伪元素选择器" tabindex="-1">4.3 伪元素选择器 <a class="header-anchor" href="#_4-3-伪元素选择器" aria-label="Permalink to &quot;4.3 伪元素选择器&quot;">​</a></h3><ul><li><p><strong>::before</strong>：在元素内容的前面插入虚拟内容，需配合content属性使用</p></li><li><p><strong>::after</strong>：在元素内容的后面插入虚拟内容，需配合content属性使用</p></li><li><p><strong>::first-letter</strong>：选择文本的第一个字母</p></li><li><p><strong>::first-line</strong>：选择文本的第一行</p></li><li><p><strong>::selection</strong>：选择用户选中的文本</p></li></ul><p>======================================================</p><h2 id="_5-基础选择器-javascript" tabindex="-1">5. 基础选择器-JavaScript <a class="header-anchor" href="#_5-基础选择器-javascript" aria-label="Permalink to &quot;5. 基础选择器-JavaScript&quot;">​</a></h2><h3 id="_5-1-id选择器" tabindex="-1">5.1 id选择器 <a class="header-anchor" href="#_5-1-id选择器" aria-label="Permalink to &quot;5.1 id选择器&quot;">​</a></h3><ul><li><p><strong>定义</strong>：#id名</p></li><li><p><strong>调用</strong>：头文件添加属性 id=&quot;id名&quot;</p></li><li><p><strong>说明</strong>：一个id选择器在一个页面只能用一次</p></li><li><p>CSS很少用，几乎不用</p></li></ul><p>======================================================</p><h2 id="_6-其他几种复合选择器" tabindex="-1">6. 其他几种复合选择器 <a class="header-anchor" href="#_6-其他几种复合选择器" aria-label="Permalink to &quot;6. 其他几种复合选择器&quot;">​</a></h2><h3 id="_6-1-子级选择器" tabindex="-1">6.1 子级选择器 <a class="header-anchor" href="#_6-1-子级选择器" aria-label="Permalink to &quot;6.1 子级选择器&quot;">​</a></h3><ul><li><p><strong>格式</strong>：选择器1 &gt; 选择器2</p></li><li><p><strong>示例</strong>：<code>div &gt; p</code>、<code>.nav &gt; ul</code></p></li><li><p><strong>作用</strong>：选择指定元素的直接子元素</p></li><li><p><strong>特点</strong>：&gt;分隔，直接关系</p></li></ul><h3 id="_6-2-并集选择器" tabindex="-1">6.2 并集选择器 <a class="header-anchor" href="#_6-2-并集选择器" aria-label="Permalink to &quot;6.2 并集选择器&quot;">​</a></h3><ul><li><p><strong>格式</strong>：选择器1, 选择器2, 选择器3...</p></li><li><p><strong>示例</strong>：<code>h1, h2, h3</code>、<code>.title, .content</code></p></li><li><p><strong>作用</strong>：同时选择多个不同的元素</p></li><li><p><strong>特点</strong>：逗号分隔，样式共享</p></li></ul><h3 id="_6-3-交集选择器" tabindex="-1">6.3 交集选择器 <a class="header-anchor" href="#_6-3-交集选择器" aria-label="Permalink to &quot;6.3 交集选择器&quot;">​</a></h3><ul><li><p><strong>格式</strong>：选择器1选择器2选择器3...（无分隔符）</p></li><li><p><strong>示例</strong>：<code>p.red</code>、<code>div.container.active</code></p></li><li><p><strong>作用</strong>：选择同时满足多个条件的元素</p></li><li><p><strong>特点</strong>：无分隔符，条件叠加</p></li></ul><p>======================================================</p>',31)])])}const b=i(n,[["render",s]]);export{_ as __pageData,b as default};
